script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const raw = input.steps?.['enter-numbers']?.numbers || '';
const numbers = raw.split(',').map(s => parseFloat(s.trim())).filter(n => !isNaN(n));
numbers.sort((a, b) => a - b);

writeFileSync('/output/result.json', JSON.stringify({
  numbers,
  count: numbers.length
}));
